package com.trademaster.ims.mobile.support.service;
import com.trademaster.ims.mobile.auth.service.CustomerAuthException;import com.trademaster.ims.mobile.checkout.repository.CustomerOrderRepository;import com.trademaster.ims.mobile.notifications.service.CustomerNotificationService;import com.trademaster.ims.mobile.support.dto.SupportDtos.*;import com.trademaster.ims.mobile.support.model.*;import com.trademaster.ims.mobile.support.repository.*;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.http.HttpStatus;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import org.springframework.util.StringUtils;import java.time.LocalDate;import java.util.*;
@Service @Transactional public class CustomerSupportService{private final SupportTicketRepository tickets;private final SupportMessageRepository messages;private final CustomerOrderRepository orders;@Autowired(required=false)private CustomerNotificationService notifications;public CustomerSupportService(SupportTicketRepository t,SupportMessageRepository m,CustomerOrderRepository o){tickets=t;messages=m;orders=o;}
@Transactional(readOnly=true)public List<TicketSummary>list(long account){return tickets.findByAccountIdOrderByUpdatedAtDesc(account).stream().map(this::summary).toList();}
public TicketDetail create(long account,CreateTicketRequest q){String order=clean(q.relatedOrderNumber());if(StringUtils.hasText(order)&&orders.findByOrderNumberAndAccountId(order,account).isEmpty())throw err(HttpStatus.BAD_REQUEST,"ORDER_NOT_FOUND","Related order was not found.");SupportTicket t=new SupportTicket();t.setTicketNumber(number());t.setAccountId(account);t.setSubject(required(q.subject(),"Subject is required."));t.setCategory(category(q.category()));t.setPriority(priority(q.priority()));t.setRelatedOrderNumber(order);t=tickets.saveAndFlush(t);SupportMessage m=new SupportMessage();m.setTicketId(t.getId());m.setSenderType(SupportMessage.SenderType.CUSTOMER);m.setMessage(required(q.message(),"Message is required."));m.setCustomerVisible(true);messages.save(m);if(notifications!=null)notifications.supportTicketCreated(account,t.getTicketNumber());return detail(t);} 
@Transactional(readOnly=true)public TicketDetail detail(long account,String number){return detail(owned(account,number));}
public TicketDetail reply(long account,String number,AddMessageRequest q){SupportTicket t=owned(account,number);if(t.getStatus()==SupportTicket.Status.CLOSED)throw err(HttpStatus.CONFLICT,"TICKET_CLOSED","This ticket is closed.");SupportMessage m=new SupportMessage();m.setTicketId(t.getId());m.setSenderType(SupportMessage.SenderType.CUSTOMER);m.setMessage(required(q.message(),"Message is required."));m.setCustomerVisible(true);messages.save(m);t.setStatus(SupportTicket.Status.OPEN);tickets.save(t);return detail(t);} 
public TicketDetail close(long account,String number){SupportTicket t=owned(account,number);t.setStatus(SupportTicket.Status.CLOSED);tickets.save(t);SupportMessage m=new SupportMessage();m.setTicketId(t.getId());m.setSenderType(SupportMessage.SenderType.SYSTEM);m.setMessage("Ticket closed by customer.");m.setCustomerVisible(true);messages.save(m);if(notifications!=null)notifications.supportTicketClosed(account,t.getTicketNumber());return detail(t);} 
private SupportTicket owned(long account,String n){return tickets.findByTicketNumberAndAccountId(n,account).orElseThrow(()->err(HttpStatus.NOT_FOUND,"SUPPORT_TICKET_NOT_FOUND","Support ticket was not found."));}private TicketDetail detail(SupportTicket t){return new TicketDetail(t.getTicketNumber(),t.getSubject(),t.getCategory().name(),t.getPriority().name(),t.getStatus().name(),t.getRelatedOrderNumber(),t.getCreatedAt(),t.getUpdatedAt(),messages.findByTicketIdAndCustomerVisibleTrueOrderByCreatedAtAsc(t.getId()).stream().map(m->new TicketMessage(m.getSenderType().name(),m.getMessage(),m.getCreatedAt())).toList());}private TicketSummary summary(SupportTicket t){return new TicketSummary(t.getTicketNumber(),t.getSubject(),t.getCategory().name(),t.getPriority().name(),t.getStatus().name(),t.getRelatedOrderNumber(),t.getCreatedAt(),t.getUpdatedAt());}
private SupportTicket.Category category(String v){try{return SupportTicket.Category.valueOf(v.trim().toUpperCase(Locale.ROOT));}catch(Exception e){throw err(HttpStatus.BAD_REQUEST,"INVALID_SUPPORT_CATEGORY","Unsupported support category.");}}private SupportTicket.Priority priority(String v){if(!StringUtils.hasText(v))return SupportTicket.Priority.NORMAL;try{return SupportTicket.Priority.valueOf(v.trim().toUpperCase(Locale.ROOT));}catch(Exception e){throw err(HttpStatus.BAD_REQUEST,"INVALID_SUPPORT_PRIORITY","Unsupported support priority.");}}private String number(){String n;do{n="SUP-"+LocalDate.now().toString().replace("-","")+"-"+UUID.randomUUID().toString().substring(0,8).toUpperCase(Locale.ROOT);}while(tickets.existsByTicketNumber(n));return n;}private String clean(String s){return s==null?null:s.replaceAll("<[^>]*>","").trim();}private String required(String s,String m){String v=clean(s);if(!StringUtils.hasText(v))throw err(HttpStatus.BAD_REQUEST,"VALIDATION_ERROR",m);return v;}private CustomerAuthException err(HttpStatus s,String c,String m){return new CustomerAuthException(s,c,m);} }